import{_ as e,o as n,c as a,a2 as d}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"AIDC绿电一体化：算电协同政策落地下的PE/VC机会图谱","description":"从PE/VC视角拆解算电协同催生的新型投资赛道—能源数字化平台、绿电聚合供应、储能运维与微电网方案","frontmatter":{"title":"AIDC绿电一体化：算电协同政策落地下的PE/VC机会图谱","description":"从PE/VC视角拆解算电协同催生的新型投资赛道—能源数字化平台、绿电聚合供应、储能运维与微电网方案"},"headers":[],"relativePath":"算电协同/AIDC绿电一体化_PE_VC机会图谱.md","filePath":"算电协同/AIDC绿电一体化_PE_VC机会图谱.md","lastUpdated":1781884211000}'),r={name:"算电协同/AIDC绿电一体化_PE_VC机会图谱.md"};function s(l,t,i,o,h,g){return n(),a("div",null,[...t[0]||(t[0]=[d(`<h1 id="aidc绿电一体化-算电协同政策落地下的pe-vc机会图谱" tabindex="-1">AIDC绿电一体化：算电协同政策落地下的PE/VC机会图谱 <a class="header-anchor" href="#aidc绿电一体化-算电协同政策落地下的pe-vc机会图谱" aria-label="Permalink to &quot;AIDC绿电一体化：算电协同政策落地下的PE/VC机会图谱&quot;">​</a></h1><blockquote><p>2026年5月15日，国家能源局正式发布《以算电协同赋能新型能源体系》，首次确立&quot;时空协同、技术协同、机制协同&quot;三协同体系。PUE≤1.15硬约束全面生效，算电协同从概念进入执行阶段。本文从PE/VC视角，拆解算电协同催生的新型投资赛道。</p></blockquote><hr><h2 id="开篇-电力需求的暴力增长" tabindex="-1">开篇：电力需求的暴力增长 <a class="header-anchor" href="#开篇-电力需求的暴力增长" aria-label="Permalink to &quot;开篇：电力需求的暴力增长&quot;">​</a></h2><p>中国数据中心用电量正以年均25%的速度增长（vs.全社会用电增速4.6%）：</p><ul><li>2024年：约<strong>1000亿kWh</strong>（占全社会用电1.9%）</li><li>2030E：约<strong>4500亿kWh</strong>（占全社会用电3.5%）</li></ul><p>仅AI用电一项，2027年预计达1340亿kWh，接近荷兰全国用电总量。这一趋势背后是AI Token调用量的暴增——从2025年的日均1000亿增长至2026年的约<strong>140万亿</strong>。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>AI算力爆发 → 芯片功耗暴增 → 电力需求激增 → 散热压力升级</span></span>
<span class="line"><span>      │              │              │              │</span></span>
<span class="line"><span>      ▼              ▼              ▼              ▼</span></span>
<span class="line"><span>  算力需求        GPU功耗        DC用电量        液冷渗透率</span></span>
<span class="line"><span>  千倍增长        1000→2300W    1000→4500亿     14%→50%+</span></span>
<span class="line"><span>      │              │              │              │</span></span>
<span class="line"><span>      └──────────────┴──────────────┴──────────────┘</span></span>
<span class="line"><span>                         ▼</span></span>
<span class="line"><span>              算电协同成为必选项</span></span></code></pre></div><hr><h2 id="政策框架已就位" tabindex="-1">政策框架已就位 <a class="header-anchor" href="#政策框架已就位" aria-label="Permalink to &quot;政策框架已就位&quot;">​</a></h2><h3 id="三协同-体系" tabindex="-1">&quot;三协同&quot;体系 <a class="header-anchor" href="#三协同-体系" aria-label="Permalink to &quot;&quot;三协同&quot;体系&quot;">​</a></h3><p>2026年5月15日的政策文件确立了算电协同的执行框架：</p><ul><li><strong>时空协同</strong>：&quot;东数西算&quot;节点与&quot;沙戈荒&quot;新能源大基地深度融合，通过跨省跨区绿电交易实现空间平衡</li><li><strong>技术协同</strong>：智能调度 + 柔性负荷调控 + 精准预测 + 高效储能的&quot;四位一体&quot;技术组合</li><li><strong>机制协同</strong>：算力-电力价格联动机制 + 绿电认证与碳减排互认 + 算力券/绿电补贴</li></ul><p>同时，新建大型数据中心PUE ≤ 1.15的硬约束于2026年全面生效，从能效端倒逼技术升级。这不是建议——是红线。不达标，不能建。</p><h3 id="电改2-0同步推进" tabindex="-1">电改2.0同步推进 <a class="header-anchor" href="#电改2-0同步推进" aria-label="Permalink to &quot;电改2.0同步推进&quot;">​</a></h3><p>目前全国已有<strong>7省正式运行</strong>电力现货市场（山西、广东、山东、甘肃、蒙西、湖北、浙江），2026年过半省份将转正。29省已发布2026年电力交易方案。电价高度分化——广东现货均价约637元/MWh，甘肃最低约145元/MWh，午间&quot;地板价&quot;常态化。</p><hr><h2 id="商业模式-四种已跑通的落地模式" tabindex="-1">商业模式：四种已跑通的落地模式 <a class="header-anchor" href="#商业模式-四种已跑通的落地模式" aria-label="Permalink to &quot;商业模式：四种已跑通的落地模式&quot;">​</a></h2><table tabindex="0"><thead><tr><th>模式</th><th>代表项目</th><th>内核</th><th>适用场景</th></tr></thead><tbody><tr><td><strong>绿电直连</strong></td><td>内蒙古乌兰察布·中金数据</td><td>新能源电站直供算力中心，100%绿电可溯源</td><td>西部大型智算中心</td></tr><tr><td><strong>绿电聚合供应</strong></td><td>甘肃庆阳/张家口/宁夏中卫</td><td>源网荷储一体化，多电站聚合供应</td><td>枢纽节点集群</td></tr><tr><td><strong>跨区电算联合调度</strong></td><td>上海电力×中国电信</td><td>DC虚拟电厂参与辅助服务</td><td>东部存量DC改造</td></tr><tr><td><strong>分布式绿电自建</strong></td><td>腾讯仪征</td><td>屋顶光伏+储能，年均消纳1210万kWh</td><td>企业自建园区</td></tr></tbody></table><h3 id="绿电-储能-液冷-一体化方案" tabindex="-1">&quot;绿电+储能+液冷&quot;一体化方案 <a class="header-anchor" href="#绿电-储能-液冷-一体化方案" aria-label="Permalink to &quot;&quot;绿电+储能+液冷&quot;一体化方案&quot;">​</a></h3><p>这是未来3年最值得关注的商业模式创新。将绿电直供、钠电/锂电储能、液冷散热打包为一个面向数据中心的完整基础设施解决方案。</p><p>一体化方案的经济性测算（以100MW智算中心为例）：</p><table tabindex="0"><thead><tr><th>组件</th><th style="text-align:center;">年化成本</th><th style="text-align:center;">节省/收益</th></tr></thead><tbody><tr><td>绿电直供（替代市电）</td><td style="text-align:center;">节省电费约0.05-0.10元/kWh</td><td style="text-align:center;">~3000-6000万/年</td></tr><tr><td>储能调峰（峰谷套利）</td><td style="text-align:center;">储能系统摊销</td><td style="text-align:center;">~800-1500万/年</td></tr><tr><td>液冷（降低PUE）</td><td style="text-align:center;">PUE从1.4降至1.15</td><td style="text-align:center;">~15%电费节省</td></tr><tr><td>碳资产收益</td><td style="text-align:center;">绿电碳减排</td><td style="text-align:center;">~200-500万/年</td></tr><tr><td><strong>综合收益</strong></td><td style="text-align:center;">—</td><td style="text-align:center;"><strong>约4000-8000万/年</strong></td></tr></tbody></table><p>目前市场上能提供这种打包方案的玩家极少，这正是PE可以推动整合的方向。</p><hr><h2 id="市场空间-绿电交易的爆发" tabindex="-1">市场空间：绿电交易的爆发 <a class="header-anchor" href="#市场空间-绿电交易的爆发" aria-label="Permalink to &quot;市场空间：绿电交易的爆发&quot;">​</a></h2><h3 id="中国绿电交易市场" tabindex="-1">中国绿电交易市场 <a class="header-anchor" href="#中国绿电交易市场" aria-label="Permalink to &quot;中国绿电交易市场&quot;">​</a></h3><table tabindex="0"><thead><tr><th>指标</th><th style="text-align:center;">2024年</th><th style="text-align:center;">2025年</th><th style="text-align:center;">2026E</th><th style="text-align:center;">2027E</th></tr></thead><tbody><tr><td>全国绿电交易电量（亿kWh）</td><td style="text-align:center;">~954</td><td style="text-align:center;">~1800</td><td style="text-align:center;">~3100</td><td style="text-align:center;">~4500</td></tr><tr><td>DC企业绿电采购占比</td><td style="text-align:center;">~8%</td><td style="text-align:center;">~15%</td><td style="text-align:center;">~25%</td><td style="text-align:center;">~35%</td></tr><tr><td>DC绿电消纳量（亿kWh）</td><td style="text-align:center;">~80</td><td style="text-align:center;">~270</td><td style="text-align:center;">~775</td><td style="text-align:center;">~1575</td></tr></tbody></table><h3 id="头部idc企业绿电采购趋势" tabindex="-1">头部IDC企业绿电采购趋势 <a class="header-anchor" href="#头部idc企业绿电采购趋势" aria-label="Permalink to &quot;头部IDC企业绿电采购趋势&quot;">​</a></h3><table tabindex="0"><thead><tr><th>企业</th><th style="text-align:center;">2025年绿电消纳</th><th style="text-align:center;">绿电占比</th><th style="text-align:center;">2030年目标</th></tr></thead><tbody><tr><td><strong>润泽科技</strong></td><td style="text-align:center;">~5.3亿kWh</td><td style="text-align:center;">~15%</td><td style="text-align:center;">100%碳中和</td></tr><tr><td><strong>万国数据</strong></td><td style="text-align:center;">~8.1亿kWh</td><td style="text-align:center;">~28%</td><td style="text-align:center;">100%可再生能源</td></tr><tr><td><strong>秦淮数据</strong></td><td style="text-align:center;">~6.7亿kWh</td><td style="text-align:center;">~35%</td><td style="text-align:center;">100%清洁能源</td></tr><tr><td><strong>光环新网</strong></td><td style="text-align:center;">~2.6亿kWh</td><td style="text-align:center;">~12%</td><td style="text-align:center;">50%绿电（2027）</td></tr></tbody></table><hr><h2 id="竞争格局-已上市公司作为景气度风向标" tabindex="-1">竞争格局：已上市公司作为景气度风向标 <a class="header-anchor" href="#竞争格局-已上市公司作为景气度风向标" aria-label="Permalink to &quot;竞争格局：已上市公司作为景气度风向标&quot;">​</a></h2><h3 id="已上市公司对比" tabindex="-1">已上市公司对比 <a class="header-anchor" href="#已上市公司对比" aria-label="Permalink to &quot;已上市公司对比&quot;">​</a></h3><table tabindex="0"><thead><tr><th>指标</th><th style="text-align:center;">润泽科技</th><th style="text-align:center;">万国数据</th><th style="text-align:center;">秦淮数据</th><th style="text-align:center;">数据港</th></tr></thead><tbody><tr><td>2025营收（亿）</td><td style="text-align:center;">56.74</td><td style="text-align:center;">~93</td><td style="text-align:center;">~52</td><td style="text-align:center;">17.21</td></tr><tr><td>营收增速</td><td style="text-align:center;"><strong>+30%</strong></td><td style="text-align:center;">+18%</td><td style="text-align:center;">+22%</td><td style="text-align:center;">0%</td></tr><tr><td>AIDC业务</td><td style="text-align:center;"><strong>44%占比</strong></td><td style="text-align:center;">~15%</td><td style="text-align:center;">~20%</td><td style="text-align:center;">接近0</td></tr><tr><td>绿电占比</td><td style="text-align:center;">~15%</td><td style="text-align:center;"><strong>~28%</strong></td><td style="text-align:center;"><strong>~35%</strong></td><td style="text-align:center;">~8%</td></tr><tr><td>估值PE</td><td style="text-align:center;">~40x</td><td style="text-align:center;">~55x</td><td style="text-align:center;">~45x</td><td style="text-align:center;"><strong>~159x</strong></td></tr></tbody></table><p><strong>关键信号</strong>：润泽科技AIDC毛利率48.5%表明下游对算力基础设施的付费意愿极强。数据港159倍PE但AIDC收入接近零——市场对传统IDC的转型溢价已经注入极高预期。</p><h3 id="未上市赛道的pe机会-一级市场" tabindex="-1">未上市赛道的PE机会（一级市场） <a class="header-anchor" href="#未上市赛道的pe机会-一级市场" aria-label="Permalink to &quot;未上市赛道的PE机会（一级市场）&quot;">​</a></h3><p>算电协同的一级市场机会并不在IDC运营本身（重资产、高资本开支），而集中在配套服务层：</p><table tabindex="0"><thead><tr><th>子方向</th><th>描述</th><th style="text-align:center;">2026E规模</th><th>PE切入点</th></tr></thead><tbody><tr><td><strong>能源数字化平台</strong></td><td>电算联合调度、绿电交易撮合、负荷预测</td><td style="text-align:center;">~50亿</td><td>有能源AI能力的SaaS平台</td></tr><tr><td><strong>绿电聚合供应服务商</strong></td><td>聚合中小绿电站、向DC规模化供应绿电</td><td style="text-align:center;">~30亿</td><td>源网荷储一体化运营平台</td></tr><tr><td><strong>储能运维服务商</strong></td><td>DC储能系统的运营维护和优化调度</td><td style="text-align:center;">~20亿</td><td>储能+DC场景垂直服务商</td></tr><tr><td><strong>微电网方案商</strong></td><td>面向DC园区的光储微电网整体方案</td><td style="text-align:center;">~40亿</td><td>有DC园区案例的微电网集成商</td></tr><tr><td><strong>碳资产管理与交易</strong></td><td>DC碳排放核算、绿电CCER开发与交易</td><td style="text-align:center;">~15亿</td><td>专注DC场景的碳资产管理公司</td></tr></tbody></table><h3 id="全球对标" tabindex="-1">全球对标 <a class="header-anchor" href="#全球对标" aria-label="Permalink to &quot;全球对标&quot;">​</a></h3><table tabindex="0"><thead><tr><th>公司</th><th>模式</th><th>启示</th></tr></thead><tbody><tr><td><strong>Soluna Holdings</strong>（US）</td><td>收购风电场→垂直整合为DC+绿电+算力</td><td>中国目前缺乏此类标的</td></tr><tr><td><strong>NextEra Energy</strong>（US）</td><td>DC+绿电打包方案（$1790亿市值）</td><td>能源巨头进入DC绿电的模式</td></tr><tr><td><strong>Colovore</strong>（US）</td><td>纯液冷DC运营商（Blackstone $9.25亿债）</td><td>绿电+液冷一体化金融模型</td></tr></tbody></table><hr><h2 id="pe投资逻辑与退出路径" tabindex="-1">PE投资逻辑与退出路径 <a class="header-anchor" href="#pe投资逻辑与退出路径" aria-label="Permalink to &quot;PE投资逻辑与退出路径&quot;">​</a></h2><h3 id="三层投资机会图谱" tabindex="-1">三层投资机会图谱 <a class="header-anchor" href="#三层投资机会图谱" aria-label="Permalink to &quot;三层投资机会图谱&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>第一层（高确定性）：</span></span>
<span class="line"><span>  储能运维服务商   ← PUE≤1.15政策驱动，刚需</span></span>
<span class="line"><span>  能源数字化平台   ← 绿电交易爆发，工具需求增长</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第二层（中高确定性）：</span></span>
<span class="line"><span>  绿电聚合供应服务商 ← 政策鼓励，聚合模式验证中</span></span>
<span class="line"><span>  微电网方案商      ← DC园区化趋势明确</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第三层（高弹性）：</span></span>
<span class="line"><span>  碳资产管理        ← 绿电CCER重启，但节奏不确定</span></span>
<span class="line"><span>  &quot;绿电+储能+液冷&quot;一体化平台 ← 整合难度大，赔率最高</span></span></code></pre></div><h3 id="退出路径" tabindex="-1">退出路径 <a class="header-anchor" href="#退出路径" aria-label="Permalink to &quot;退出路径&quot;">​</a></h3><table tabindex="0"><thead><tr><th>退出路径</th><th>适合标的</th><th style="text-align:center;">预期回报</th><th style="text-align:center;">时间周期</th></tr></thead><tbody><tr><td>战略收购（IDC/能源集团）</td><td>能源数字化/储能运维</td><td style="text-align:center;">3-5x</td><td style="text-align:center;">3-5年</td></tr><tr><td>卖给产业基金</td><td>绿电聚合供应</td><td style="text-align:center;">3-4x</td><td style="text-align:center;">3-5年</td></tr><tr><td>被AIDC运营商垂直整合</td><td>微电网/储能运维</td><td style="text-align:center;">3-5x</td><td style="text-align:center;">2-4年</td></tr></tbody></table><h3 id="仓位建议-核心-卫星-期权" tabindex="-1">仓位建议：核心+卫星+期权 <a class="header-anchor" href="#仓位建议-核心-卫星-期权" aria-label="Permalink to &quot;仓位建议：核心+卫星+期权&quot;">​</a></h3><ul><li><strong>核心仓位（60%）</strong>：能源数字化平台 + 储能运维服务商（中确定性、稳健回报）</li><li><strong>卫星仓位（30%）</strong>：绿电聚合供应 + 微电网方案商（中高弹性）</li><li><strong>期权仓位（10%）</strong>：碳资产管理 + 一体化平台（高赔率）</li></ul><hr><h2 id="催化剂时间线" tabindex="-1">催化剂时间线 <a class="header-anchor" href="#催化剂时间线" aria-label="Permalink to &quot;催化剂时间线&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">时间</th><th>事件</th><th style="text-align:center;">影响</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>2026年</strong></td><td>PUE≤1.15全面执行</td><td style="text-align:center;">全行业洗牌，利好绿电+液冷运营</td></tr><tr><td style="text-align:center;"><strong>2026H2</strong></td><td>第二批算电协同试点</td><td style="text-align:center;">新增绿电聚合供应配额</td></tr><tr><td style="text-align:center;"><strong>2026Q4</strong></td><td>绿电CCER有望重启</td><td style="text-align:center;">碳资产价值释放</td></tr><tr><td style="text-align:center;"><strong>2027H1</strong></td><td>日均Token调用量突破300万亿</td><td style="text-align:center;">AIDC需求再上台阶</td></tr><tr><td style="text-align:center;"><strong>2027</strong></td><td>绿电交易纳入碳市场</td><td style="text-align:center;">绿电溢价机制完善</td></tr></tbody></table><hr><h2 id="风险提示" tabindex="-1">风险提示 <a class="header-anchor" href="#风险提示" aria-label="Permalink to &quot;风险提示&quot;">​</a></h2><ol><li><strong>电网改革进度不确定</strong>：绿电直供和跨区交易依赖电网改革，落地节奏可能不及预期</li><li><strong>绿电溢价波动</strong>：绿电交易价格受供需关系影响，溢价可能收窄</li><li><strong>AI资本开支周期性</strong>：若全球AI投资放缓，AIDC的绿电需求将受影响</li><li><strong>竞争加剧</strong>：能源集团（国网、华能等）直接入场将压缩第三方服务商的利润空间</li><li><strong>存量DC改造成本高</strong>：老旧DC改造的经济性可能不达预期</li></ol><hr><p><strong>核心结论</strong>：AIDC绿电一体化是算电协同政策催生的新型投资赛道。已上市公司数据（润泽科技AIDC毛利率48.5%等）验证了下游需求的真实性。PE的核心机会不在IDC运营本身，而在配套的<strong>能源数字化平台、绿电聚合供应、储能运维和微电网方案</strong>这四个子方向。当前市场空白较大，先进入者有机会建立先发优势。</p><p><em>本文基于公开数据整理与行业分析，不构成投资建议。</em></p>`,57)])])}const x=e(r,[["render",s]]);export{p as __pageData,x as default};
